{
  "workflow_id": "wf_7xk9p2q4",
  "name": "Auto-log expense reports to sheet",
  "description": "Automatically extracts expense details from emails and appends them to the team expenses sheet.",
  "created_from_transcript": true,
  "trigger": {
    "type": "email_received",
    "config": {
      "from_filter": null,
      "subject_filter": "Expense Report",
      "match": "contains"
    }
  },
  "steps": [
    {
      "id": "step_1",
      "name": "Extract expense details from email",
      "action": "gmail.read_email",
      "config": {
        "extract_fields": [
          "date",
          "amount",
          "category",
          "description",
          "sender_name"
        ]
      },
      "output_variable": "expense_data"
    },
    {
      "id": "step_2",
      "name": "Append expense to team sheet",
      "action": "sheets.append_row",
      "config": {
        "spreadsheet_id": "{{user.spreadsheet_id}}",
        "sheet_name": "Submitted",
        "row_data": [
          "{{expense_data.date}}",
          "{{expense_data.amount}}",
          "{{expense_data.category}}",
          "{{expense_data.description}}",
          "{{expense_data.sender_name}}",
          "{{workflow.run_timestamp}}"
        ]
      }
    }
  ],
  "meta": {
    "estimated_time_saved_minutes": 15,
    "runs": 0,
    "last_run": null,
    "status": "active"
  }
}

{
  "workflow_id": "wf_7x9Kp2Lm",
  "name": "Auto-log supplier invoices",
  "description": "Automatically extracts key invoice details from supplier emails and appends them to the tracking sheet.",
  "created_from_transcript": true,
  "trigger": {
    "type": "email_received",
    "config": {
      "from_filter": "@acme-widgets.com, @beta-logistics.com, @gamma-parts.com",
      "subject_filter": "invoice",
      "match": "contains"
    }
  },
  "steps": [
    {
      "id": "step_1",
      "name": "Read invoice email",
      "action": "gmail.read_email",
      "config": {
        "extract_fields": [
          {
            "name": "invoice_number",
            "pattern": "Invoice No\\.?:?\\s*([A-Z0-9-]+)"
          },
          {
            "name": "invoice_date",
            "pattern": "Date\\.?:?\\s*(\\d{1,2}/\\d{1,2}/\\d{2,4})"
          },
          {
            "name": "total_amount",
            "pattern": "Total\\.?:?\\s*\\$?([0-9,.]+)"
          },
          {
            "name": "po_number",
            "pattern": "PO\\.?:?\\s*([A-Z0-9-]+)",
            "optional": true
          },
          {
            "name": "supplier_name",
            "pattern": null,
            "value": "{{trigger.from_domain}}"
          }
        ]
      },
      "output_variable": "invoice_data"
    },
    {
      "id": "step_2",
      "name": "Append to tracking sheet",
      "action": "sheets.append_row",
      "config": {
        "spreadsheet_id": "{{user.spreadsheet_id}}",
        "sheet_name": "Incoming",
        "row_data": [
          "{{invoice_data.invoice_number}}",
          "{{invoice_data.invoice_date}}",
          "{{invoice_data.total_amount}}",
          "{{invoice_data.po_number}}",
          "{{invoice_data.supplier_name}}"
        ]
      }
    }
  ],
  "meta": {
    "estimated_time_saved_minutes": 20,
    "runs": 0,
    "last_run": null,
    "status": "active"
  }
}

{
  "workflow_id": "wf_8a3d9f2e",
  "name": "Auto-Acknowledge Client Feedback",
  "description": "Automatically sends a thank-you reply to client feedback emails from @clientco.com.",
  "created_from_transcript": true,
  "trigger": {
    "type": "email_received",
    "config": {
      "from_filter": "@clientco.com",
      "subject_filter": "Feedback,Thoughts",
      "match": "contains"
    }
  },
  "steps": [
    {
      "id": "step_1",
      "name": "Extract client name from email",
      "action": "gmail.read_email",
      "config": {
        "extract_fields": [
          "from_name"
        ]
      },
      "output_variable": "client_name"
    },
    {
      "id": "step_2",
      "name": "Send thank-you reply",
      "action": "gmail.send_email",
      "config": {
        "to": "{{email.from}}",
        "subject": "Thank You for Your Feedback",
        "body": "Thanks so much for sharing your thoughts, {{client_name}}! We\u2019ll review your feedback and get back to you soon."
      }
    }
  ],
  "meta": {
    "estimated_time_saved_minutes": 15,
    "runs": 0,
    "last_run": null,
    "status": "active"
  }
}

{
  "workflow_id": "wf_7x9k2p4m",
  "name": "Weekly Client Signup Recap",
  "description": "Automatically pulls new client signups from the spreadsheet and emails a formatted summary to the management team every Friday.",
  "created_from_transcript": true,
  "trigger": {
    "type": "manual",
    "config": {}
  },
  "steps": [
    {
      "id": "step_1",
      "name": "Read new client signups",
      "action": "sheets.read_rows",
      "config": {
        "spreadsheet_id": "{{user.spreadsheet_id}}",
        "sheet_name": "New Signups",
        "range": "A2:D"
      },
      "output_variable": "new_signups"
    },
    {
      "id": "step_2",
      "name": "Format email body",
      "action": "condition",
      "config": {
        "if": "{{new_signups.length}} > 0",
        "then": "step_3",
        "else": "step_4"
      }
    },
    {
      "id": "step_3",
      "name": "Generate summary email",
      "action": "gmail.send_email",
      "config": {
        "to": "management-team@company.com",
        "subject": "Weekly Client Signup Recap - {{workflow.run_timestamp | date('MMMM d, yyyy')}}",
        "body": "<p>Hi Team,</p><p>Here are the new client signups for this week:</p><ul>{{#new_signups}}<li><strong>{{Client Name}}</strong> - {{Signup Date}} ({{Service Requested}})</li>{{/new_signups}}</ul><p>Best,<br>Natalie</p>"
      }
    },
    {
      "id": "step_4",
      "name": "Send no-signups email",
      "action": "gmail.send_email",
      "config": {
        "to": "management-team@company.com",
        "subject": "Weekly Client Signup Recap - {{workflow.run_timestamp | date('MMMM d, yyyy')}}",
        "body": "<p>Hi Team,</p><p>No new client signups this week.</p><p>Best,<br>Natalie</p>"
      }
    }
  ],
  "meta": {
    "estimated_time_saved_minutes": 60,
    "runs": 0,
    "last_run": null,
    "status": "active"
  }
}

{
  "workflow_id": "wf_7xk9p2q4",
  "name": "Supplier Email Triage",
  "description": "Automatically confirm receipt of supplier emails and forward shipping details to warehouse when needed.",
  "created_from_transcript": true,
  "trigger": {
    "type": "email_received",
    "config": {
      "from_filter": [
        "acme-corp.com",
        "globex-logistics.com"
      ],
      "subject_filter": null,
      "match": "contains"
    }
  },
  "steps": [
    {
      "id": "step_1",
      "name": "Check sender",
      "action": "condition",
      "config": {
        "if": "{{trigger.from}} contains 'acme-corp.com'",
        "then": "step_2",
        "else": "step_3"
      }
    },
    {
      "id": "step_2",
      "name": "Reply to Acme",
      "action": "gmail.send_email",
      "config": {
        "to": "{{trigger.from}}",
        "subject": "Re: {{trigger.subject}}",
        "body": "Hi,\n\nGot it, thanks!\n\nBest,\nNatalie"
      }
    },
    {
      "id": "step_3",
      "name": "Extract order number from Globex email",
      "action": "gmail.read_email",
      "config": {
        "extract_fields": [
          "order_number"
        ]
      },
      "output_variable": "extracted_data"
    },
    {
      "id": "step_4",
      "name": "Forward email to warehouse",
      "action": "gmail.send_email",
      "config": {
        "to": "warehouse@ourcompany.com",
        "subject": "Fwd: {{trigger.subject}} (Globex Shipping Details)",
        "body": "{{trigger.body}}"
      }
    },
    {
      "id": "step_5",
      "name": "Update tracking sheet",
      "action": "sheets.append_row",
      "config": {
        "spreadsheet_id": "{{user.spreadsheet_id}}",
        "sheet_name": "Supplier Tracking",
        "row_data": [
          "{{extracted_data.order_number}}",
          "{{workflow.run_timestamp}}"
        ]
      }
    }
  ],
  "meta": {
    "estimated_time_saved_minutes": 15,
    "runs": 0,
    "last_run": null,
    "status": "active"
  }
}

{
  "workflow_id": "wf_7x9k2pLm",
  "name": "Auto-route info@ emails to teams",
  "description": "Automatically forwards emails from the info@ inbox to the correct team based on subject or content, and flags unmatched emails for review.",
  "created_from_transcript": true,
  "trigger": {
    "type": "email_received",
    "config": {
      "from_filter": "info@company.com",
      "subject_filter": null,
      "match": null
    }
  },
  "steps": [
    {
      "id": "step_1",
      "name": "Check for PR-related emails",
      "action": "condition",
      "config": {
        "if": "({{email.subject}} contains 'press inquiry') OR ({{email.subject}} contains 'media')",
        "then": "step_2",
        "else": "step_3"
      }
    },
    {
      "id": "step_2",
      "name": "Forward to PR team",
      "action": "gmail.send_email",
      "config": {
        "to": "pr-team@company.com",
        "subject": "FWD: {{email.subject}}",
        "body": "{{email.body}}"
      }
    },
    {
      "id": "step_3",
      "name": "Check for business development emails",
      "action": "condition",
      "config": {
        "if": "({{email.subject}} contains 'partnership') OR ({{email.subject}} contains 'collaboration')",
        "then": "step_4",
        "else": "step_5"
      }
    },
    {
      "id": "step_4",
      "name": "Forward to business development",
      "action": "gmail.send_email",
      "config": {
        "to": "bd-team@company.com",
        "subject": "FWD: {{email.subject}}",
        "body": "{{email.body}}"
      }
    },
    {
      "id": "step_5",
      "name": "Check for accounting-related emails",
      "action": "condition",
      "config": {
        "if": "({{email.from}} contains '@vendor.com') AND ({{email.subject}} contains 'invoice')",
        "then": "step_6",
        "else": "step_7"
      }
    },
    {
      "id": "step_6",
      "name": "Forward to accounting",
      "action": "gmail.send_email",
      "config": {
        "to": "accounting@company.com",
        "subject": "FWD: {{email.subject}}",
        "body": "{{email.body}}"
      }
    },
    {
      "id": "step_7",
      "name": "Check email body for product or sales questions",
      "action": "condition",
      "config": {
        "if": "({{email.subject}} contains 'Hello') OR ({{email.subject}} contains 'Question')",
        "then": "step_8",
        "else": "step_10"
      }
    },
    {
      "id": "step_8",
      "name": "Read email body for routing",
      "action": "gmail.read_email",
      "config": {
        "extract_fields": [
          "body"
        ]
      },
      "output_variable": "email_body"
    },
    {
      "id": "step_9",
      "name": "Route based on body content",
      "action": "condition",
      "config": {
        "if": "({{email_body}} contains 'product issue') OR ({{email_body}} contains 'bug')",
        "then": "step_11",
        "else": "step_12"
      }
    },
    {
      "id": "step_10",
      "name": "Flag unmatched emails for review",
      "action": "gmail.send_email",
      "config": {
        "to": "{{user.email}}",
        "subject": "Unassigned: {{email.subject}}",
        "body": "This email didn\u2019t match any routing rules. Please review: {{email.body}}"
      }
    },
    {
      "id": "step_11",
      "name": "Forward to product team",
      "action": "gmail.send_email",
      "config": {
        "to": "product-team@company.com",
        "subject": "FWD: {{email.subject}} (Product Issue)",
        "body": "{{email.body}}"
      }
    },
    {
      "id": "step_12",
      "name": "Forward to sales team",
      "action": "gmail.send_email",
      "config": {
        "to": "sales@company.com",
        "subject": "FWD: {{email.subject}} (Sales Question)",
        "body": "{{email.body}}"
      }
    }
  ],
  "meta": {
    "estimated_time_saved_minutes": 45,
    "runs": 0,
    "last_run": null,
    "status": "active"
  }
}

