{
  "workflow_id": "wf_7x9Kp2Lm",
  "name": "Customer Support Email Triage",
  "description": "Automatically routes urgent customer emails to the correct team and logs all emails in a spreadsheet.",
  "created_from_transcript": true,
  "trigger": {
    "type": "email_received",
    "config": {
      "from_filter": null,
      "subject_filter": "urgent, ASAP, help",
      "match": "contains"
    }
  },
  "steps": [
    {
      "id": "step_1",
      "name": "Check if email is urgent",
      "action": "condition",
      "config": {
        "if": "{{trigger.subject}} contains 'urgent' or {{trigger.subject}} contains 'ASAP' or {{trigger.subject}} contains 'help'",
        "then": "step_2",
        "else": "step_4"
      }
    },
    {
      "id": "step_2",
      "name": "Determine forwarding destination",
      "action": "condition",
      "config": {
        "if": "{{trigger.body}} contains 'billing' or {{trigger.body}} contains 'payment'",
        "then": "step_3a",
        "else": "step_3b"
      }
    },
    {
      "id": "step_3a",
      "name": "Forward to finance team",
      "action": "gmail.send_email",
      "config": {
        "to": "finance-team@company.com",
        "subject": "URGENT: {{trigger.subject}}",
        "body": "Forwarded from {{trigger.from}}:\n\n{{trigger.body}}"
      }
    },
    {
      "id": "step_3b",
      "name": "Forward to IT support team",
      "action": "gmail.send_email",
      "config": {
        "to": "it-support@company.com",
        "subject": "URGENT: {{trigger.subject}}",
        "body": "Forwarded from {{trigger.from}}:\n\n{{trigger.body}}"
      }
    },
    {
      "id": "step_4",
      "name": "Log email in spreadsheet",
      "action": "sheets.append_row",
      "config": {
        "spreadsheet_id": "{{user.spreadsheet_id}}",
        "sheet_name": "Support Log",
        "row_data": [
          "{{workflow.run_timestamp}}",
          "{{trigger.from}}",
          "{{trigger.subject}}",
          "{{step_1.config.if}}"
        ]
      }
    }
  ],
  "meta": {
    "estimated_time_saved_minutes": 45,
    "runs": 0,
    "last_run": null,
    "status": "active"
  }
}

{
  "workflow_id": "wf_7x9k2p4m",
  "name": "Contractor Invoice Triage",
  "description": "Automatically routes contractor invoices to accounting or requests missing details from the sender, and logs processed invoices in a spreadsheet.",
  "created_from_transcript": true,
  "trigger": {
    "type": "email_received",
    "config": {
      "from_filter": [
        "john@smithconsulting.com",
        "lisa@designpros.net",
        "builditllc.com"
      ],
      "subject_filter": "Invoice",
      "match": "contains"
    }
  },
  "steps": [
    {
      "id": "step_1",
      "name": "Read invoice email",
      "action": "gmail.read_email",
      "config": {
        "extract_fields": [
          "from",
          "subject",
          "invoice_number",
          "project_name",
          "amount"
        ]
      },
      "output_variable": "invoice_data"
    },
    {
      "id": "step_2",
      "name": "Check for missing details",
      "action": "condition",
      "config": {
        "if": "{{invoice_data.invoice_number}} == null OR {{invoice_data.project_name}} == null OR {{invoice_data.amount}} == null",
        "then": "step_3",
        "else": "step_4"
      }
    },
    {
      "id": "step_3",
      "name": "Request missing details",
      "action": "gmail.send_email",
      "config": {
        "to": "{{invoice_data.from}}",
        "subject": "Re: {{invoice_data.subject}} - Missing Information",
        "body": "Hi,\n\nWe received your invoice ({{invoice_data.subject}}), but it looks like some required details are missing. Could you please provide the following:\n- Invoice number\n- Project name\n- Amount\n\nThanks!\nNatalie"
      }
    },
    {
      "id": "step_4",
      "name": "Forward to accounting",
      "action": "gmail.send_email",
      "config": {
        "to": "accounting@ourcompany.com",
        "subject": "{{invoice_data.subject}} - Approved",
        "body": "Hi Accounting Team,\n\nPlease process the attached invoice. Here are the details:\n- Contractor: {{invoice_data.from}}\n- Invoice #: {{invoice_data.invoice_number}}\n- Project: {{invoice_data.project_name}}\n- Amount: {{invoice_data.amount}}\n\nThanks,\nNatalie"
      }
    },
    {
      "id": "step_5",
      "name": "Log invoice in spreadsheet",
      "action": "sheets.append_row",
      "config": {
        "spreadsheet_id": "{{user.spreadsheet_id}}",
        "sheet_name": "Contractor Invoices",
        "row_data": [
          "{{workflow.run_timestamp}}",
          "{{invoice_data.from}}",
          "{{invoice_data.invoice_number}}",
          "{{invoice_data.project_name}}",
          "{{invoice_data.amount}}",
          "Processed"
        ]
      }
    }
  ],
  "meta": {
    "estimated_time_saved_minutes": 30,
    "runs": 0,
    "last_run": null,
    "status": "active"
  }
}

