{
  "workflow_id": "wf_7x9k2p4m",
  "name": "Weekly Team Stats Email",
  "description": "Automatically sends weekly team stats from a Google Sheet to Natalie's manager every Friday at 4 PM.",
  "created_from_transcript": true,
  "trigger": {
    "type": "manual",
    "config": {
      "schedule": {
        "day_of_week": "Friday",
        "time": "16:00"
      }
    }
  },
  "steps": [
    {
      "id": "step_1",
      "name": "Read weekly stats from Google Sheet",
      "action": "sheets.read_rows",
      "config": {
        "spreadsheet_id": "{{user.spreadsheet_id}}",
        "sheet_name": "Summary",
        "range": "B5:E5"
      },
      "output_variable": "weekly_stats"
    },
    {
      "id": "step_2",
      "name": "Format email with stats",
      "action": "gmail.send_email",
