{
  "workflow_id": "wf_7x9KpL2m",
  "name": "Contractor Invoice Triage",
  "description": "Automatically routes contractor invoices to the correct recipient and logs details in a spreadsheet.",
  "created_from_transcript": true,
  "trigger": {
    "type": "email_received",
    "config": {
      "from_filter": "@freelancepros.com,@contractorsRus.net,contractor1@personal.com,contractor2@personal.com",
      "subject_filter": "invoice",
      "match": "contains"
    }
  },
  "steps": [
    {
      "id": "step_1",
      "name": "Extract invoice details",
      "action": "gmail.read_email",
      "config": {
        "extract_fields": [
          "sender",
          "subject",
          "invoice_number",
          "amount",
          "contractor_name"
        ]
      },
      "output_variable": "invoice_data"
    },
    {
      "id": "step_2",
      "name": "Check if sender is known",
      "action": "condition",
      "config": {
        "if": "{{invoice_data.sender}} not in ['@freelancepros.com', '@contractorsRus.net', 'contractor1@personal.com', 'contractor2@personal.com']",
        "then": "step_6",
        "else": "step_3"
      }
    },
    {
      "id": "step_3",
      "name": "Determine recipient",
      "action": "condition",
      "config": {
        "if": "{{invoice_data.subject}} contains 'project X'",
        "then": "step_4",
        "else": "step_5"
      }
    },
    {
      "id": "step_4",
      "name": "Forward to project manager",
      "action": "gmail.send_email",
      "config": {
        "to": "project.manager@company.com",
        "subject": "Invoice for Review: {{invoice_data.invoice_number}}",
        "body": "Hi,\n\nPlease review this invoice from {{invoice_data.contractor_name}} for Project X. Let me know if you need anything else.\n\nThanks,\nNatalie"
      }
    },
    {
      "id": "step_5",
      "name": "Forward to accounting",
      "action": "gmail.send_email",
      "config": {
        "to": "accounting@company.com",
        "subject": "Invoice for Processing: {{invoice_data.invoice_number}}",
        "body": "Hi,\n\nPlease process this invoice from {{invoice_data.contractor_name}} for {{invoice_data.amount}}.\n\nThanks,\nNatalie"
      }
    },
    {
      "id": "step_6",
      "name": "Flag for manual review",
      "action": "gmail.send_email",
      "config": {
        "to": "{{user.email}}",
        "subject": "New Contractor Invoice: Manual Review Needed",
        "body": "Hi Natalie,\n\nAn invoice from a new sender ({{invoice_data.sender}}) has arrived. Please review it and decide how to handle it.\n\nThanks,\nAria"
      }
    },
    {
      "id": "step_7",
      "name": "Log invoice in spreadsheet",
      "action": "sheets.append_row",
      "config": {
        "spreadsheet_id": "{{user.spreadsheet_id}}",
        "sheet_name": "Invoices",
        "row_data": [
          "{{workflow.run_timestamp}}",
          "{{invoice_data.invoice_number}}",
          "{{invoice_data.contractor_name}}",
          "{{invoice_data.amount}}",
          "{{step_4.config.to if step_3.config.if else step_5.config.to}}"
        ]
      }
    },
    {
      "id": "step_8",
      "name": "Reply for more details if needed",
      "action": "condition",
      "config": {
        "if": "{{invoice_data.amount}} is empty or {{invoice_data.invoice_number}} is empty",
        "then": "step_9",
        "else": "step_10"
      }
    },
    {
      "id": "step_9",
      "name": "Request missing details",
      "action": "gmail.send_email",
      "config": {
        "to": "{{invoice_data.sender}}",
        "subject": "Re: {{invoice_data.subject}}",
        "body": "Hi,\n\nThanks for sending your invoice. Could you please clarify the following details?\n- Invoice number\n- Total amount\n\nThanks!\nNatalie"
      }
    },
    {
      "id": "step_10",
      "name": "Complete workflow",
      "action": "condition",
      "config": {
        "if": "true",
        "then": null,
        "else": null
      }
    }
  ],
  "meta": {
    "estimated_time_saved_minutes": 45,
    "runs": 0,
    "last_run": null,
    "status": "active"
  }
}

