{
  "workflow_id": "wf_7x9k2p4m",
  "name": "Customer Email Triage",
  "description": "Automatically sorts and routes incoming customer emails based on urgency and content.",
  "created_from_transcript": true,
  "trigger": {
    "type": "email_received",
    "config": {
      "from_filter": null,
      "subject_filter": "Sales",
      "match": "exact"
    }
  },
  "steps": [
    {
      "id": "step_1",
      "name": "Check for urgent keywords",
      "action": "condition",
      "config": {
        "if": "({{email.subject}} contains 'urgent' or {{email.subject}} contains 'help' or {{email.subject}} contains 'refund' or {{email.subject}} contains 'broken' or {{email.subject}} contains 'billing' or {{email.subject}} contains 'payment') or ({{email.body}} contains 'urgent' or {{email.body}} contains 'help' or {{email.body}} contains 'refund' or {{email.body}} contains 'broken' or {{email.body}} contains 'billing' or {{email.body}} contains 'payment')",
        "then": "step_2",
        "else": "step_3"
      }
    },
    {
      "id": "step_2",
      "name": "Forward urgent email to support",
      "action": "gmail.send_email",
      "config": {
        "to": "support@ourcompany.com",
        "subject": "High Priority: {{email.subject}}",
        "body": "High priority\u2014please handle ASAP.\n\nOriginal email:\nFrom: {{email.from}}\nSubject: {{email.subject}}\n\n{{email.body}}"
      }
    },
    {
      "id": "step_3",
      "name": "Check for general questions",
      "action": "condition",
      "config": {
        "if": "{{email.body}} contains '?' or {{email.subject}} contains 'question' or {{email.subject}} contains 'how' or {{email.subject}} contains 'what'",
        "then": "step_4",
        "else": "step_5"
      }
    },
    {
      "id": "step_4",
      "name": "Reply with FAQ",
      "action": "gmail.send_email",
      "config": {
        "to": "{{email.from}}",
        "subject": "Re: {{email.subject}}",
        "body": "Hi there,\n\nThanks for reaching out! Here\u2019s a link to our FAQ that might help: [FAQ Link]. If you need further assistance, feel free to reply to this email.\n\nBest,\nNatalie"
      }
    },
    {
      "id": "step_5",
      "name": "Check for positive feedback",
      "action": "condition",
      "config": {
        "if": "{{email.body}} contains 'thank' or {{email.body}} contains 'great' or {{email.body}} contains 'awesome' or {{email.subject}} contains 'thank'",
        "then": "step_6",
        "else": "step_7"
      }
    },
    {
      "id": "step_6",
      "name": "Archive positive email",
      "action": "gmail.send_email",
      "config": {
        "to": "{{user.email}}",
        "subject": "Archived: {{email.subject}}",
        "body": "This email has been archived as positive feedback.\n\nFrom: {{email.from}}\nSubject: {{email.subject}}"
      }
    },
    {
      "id": "step_7",
      "name": "Log unclassified email",
      "action": "sheets.append_row",
      "config": {
        "spreadsheet_id": "{{user.spreadsheet_id}}",
        "sheet_name": "Unclassified Emails",
        "row_data": [
          "{{workflow.run_timestamp}}",
          "{{email.from}}",
          "{{email.subject}}",
          "{{email.body}}"
        ]
      }
    }
  ],
  "meta": {
    "estimated_time_saved_minutes": 45,
    "runs": 0,
    "last_run": null,
    "status": "active"
  }
}

