{
  "workflow_id": "wf_7x9k2pq4",
  "name": "Auto-Log Team Expense Reports",
  "description": "Automatically extracts expense details from team emails and logs them to the expense tracking sheet.",
  "created_from_transcript": true,
  "trigger": {
    "type": "email_received",
    "config": {
      "from_filter": "@yourcompany.com",
      "subject_filter": "Expense Report -",
      "match": "contains"
    }
  },
  "steps": [
    {
      "id": "step_1",
      "name": "Read Expense Email",
      "action": "gmail.read_email",
      "config": {
        "extract_fields": [
          "from",
          "subject",
          "date",
          {
            "name": "amount",
            "pattern": "(Total|Amount): \\$([0-9]+\\.[0-9]{2})"
          }
        ]
      },
      "output_variable": "expense_data"
    },
    {
      "id": "step_2",
      "name": "Add to Expense Sheet",
      "action": "sheets.append_row",
      "config": {
        "spreadsheet_id": "{{user.spreadsheet_id}}",
        "sheet_name": "Submitted",
        "row_data": [
          "{{expense_data.from}}",
          "{{expense_data.subject}}",
          "{{expense_data.date}}",
          "{{expense_data.amount}}"
        ]
      }
    },
    {
      "id": "step_3",
      "name": "Move to Processed Folder",
      "action": "gmail.search_emails",
      "config": {
        "query": "subject:'{{expense_data.subject}}' from:'{{expense_data.from}}'",
        "max_results": 1
      },
      "output_variable": "email_to_move"
    },
    {
      "id": "step_4",
      "name": "Label as Processed",
      "action": "gmail.send_email",
      "config": {
        "to": "{{user.email}}",
        "subject": "",
        "body": "",
        "action": "label",
        "label": "Processed Expenses",
        "message_id": "{{email_to_move.0.id}}"
      }
    }
  ],
  "meta": {
