{
  "workflow_id": "wf_7xY9pL2Q",
  "name": "Auto-log supplier invoices to sheet",
  "description": "Automatically extracts invoice details from supplier emails and appends them to the tracking spreadsheet during work hours.",
  "created_from_transcript": true,
  "trigger": {
    "type": "email_received",
    "config": {
      "from_filter": null,
      "subject_filter": "Invoice",
      "match": "contains"
    }
  },
  "steps": [
    {
      "id": "step_1",
      "name": "Extract invoice details from email",
      "action": "gmail.read_email",
      "config": {
        "extract_fields": [
          "date",
          "from",
          "subject",
          "body_text"
        ]
      },
      "output_variable": "email_data"
    },
    {
      "id": "step_2",
      "name": "Parse supplier name from sender",
      "action": "condition",
      "config": {
        "if": "'{{email_data.from}}' contains '@supplier1.com'",
        "then": "Supplier One",
        "else": "step_3"
      },
      "output_variable": "supplier_name"
    },
    {
      "id": "step_3",
      "name": "Parse supplier name (fallback)",
      "action": "condition",
      "config": {
        "if": "'{{email_data.from}}' contains '@supplier2.com'",
        "then": "Supplier Two",
        "else": "step_4"
      }
    },
    {
      "id": "step_4",
      "name": "Parse supplier name (final fallback)",
      "action": "condition",
      "config": {
        "if": "'{{email_data.from}}' contains '@supplier3.com'",
        "then": "Supplier Three",
        "else": "Unknown Supplier"
      },
      "output_variable": "supplier_name"
    },
    {
      "id": "step_5",
      "name": "Extract invoice number from subject",
      "action": "condition",
      "config": {
        "if": "'{{email_data.subject}}' matches regex 'Invoice #([A-Z0-9-]+)'",
        "then": "{{regex_match}}",
        "else": "Not Found"
      },
      "output_variable": "invoice_number"
    },
    {
      "id": "step_6",
      "name": "Extract amount from email body",
      "action": "condition",
      "config": {
        "if": "'{{email_data.body_text}}' matches regex 'Amount: \\$([0-9]+\\.[0-9]{2})'",
        "then": "{{regex_match}}",
        "else": "0.00"
      },
      "output_variable": "invoice_amount"
    },
    {
      "id": "step_7",
      "name": "Append invoice to tracking sheet",
      "action": "sheets.append_row",
      "config": {
        "spreadsheet_id": "{{user.spreadsheet_id}}",
        "sheet_name": "Supplier Invoices",
        "row_data": [
          "{{email_data.date}}",
          "{{supplier_name}}",
          "{{invoice_amount}}",
          "{{invoice_number}}"
        ]
      }
    }
  ],
  "meta": {
    "estimated_time_saved_minutes": 15,
    "runs": 0,
    "last_run": null,
    "status": "active"
  }
}

{
  "workflow_id": "wf_aB3dE7fG",
  "name": "Customer Support Email Triage",
  "description": "Automatically routes urgent customer emails to the correct team and replies to non-urgent ones with templates.",
  "created_from_transcript": true,
  "trigger": {
    "type": "email_received",
    "config": {
      "from_filter": "support@ourcompany.com",
      "subject_filter": null,
      "match": null
    }
  },
  "steps": [
    {
      "id": "step_1",
      "name": "Check for urgency keywords",
      "action": "gmail.read_email",
      "config": {
        "extract_fields": [
          "subject",
          "body"
        ]
      },
      "output_variable": "email_content"
    },
    {
      "id": "step_2",
      "name": "Determine if email is urgent",
      "action": "condition",
      "config": {
        "if": "({{email_content.subject}} contains 'URGENT' OR {{email_content.subject}} contains 'HELP' OR {{email_content.body}} contains 'refund' OR {{email_content.body}} contains 'cancel')",
        "then": "step_3",
        "else": "step_5"
      }
    },
    {
      "id": "step_3",
      "name": "Identify forwarding team",
      "action": "condition",
      "config": {
        "if": "{{email_content.body}} contains 'shipping'",
        "then": "step_4a",
        "else": "step_4b"
      }
    },
    {
      "id": "step_4a",
      "name": "Forward to shipping team",
      "action": "gmail.send_email",
      "config": {
        "to": "shipping@ourcompany.com",
        "subject": "URGENT: Forwarded Support Email - {{email_content.subject}}",
        "body": "This email was flagged as urgent and relates to shipping. Original email below:\n\n{{email_content.body}}"
      }
    },
    {
      "id": "step_4b",
      "name": "Check for billing keywords",
      "action": "condition",
      "config": {
        "if": "{{email_content.body}} contains 'billing' OR {{email_content.body}} contains 'refund'",
        "then": "step_4c",
        "else": "step_4d"
      }
    },
    {
      "id": "step_4c",
      "name": "Forward to billing team",
      "action": "gmail.send_email",
      "config": {
        "to": "billing@ourcompany.com",
        "subject": "URGENT: Forwarded Support Email - {{email_content.subject}}",
        "body": "This email was flagged as urgent and relates to billing. Original email below:\n\n{{email_content.body}}"
      }
    },
    {
      "id": "step_4d",
      "name": "Forward to support leads",
      "action": "gmail.send_email",
      "config": {
        "to": "support-leads@ourcompany.com",
        "subject": "URGENT: Forwarded Support Email - {{email_content.subject}}",
        "body": "This email was flagged as urgent but doesn\u2019t match shipping or billing. Original email below:\n\n{{email_content.body}}"
      }
    },
    {
      "id": "step_5",
      "name": "Reply with general template",
      "action": "gmail.send_email",
      "config": {
        "to": "{{email_content.from}}",
        "subject": "Re: {{email_content.subject}}",
        "body": "Hi there,\n\nThanks for reaching out! We\u2019ve received your email and will get back to you as soon as possible. In the meantime, you might find the answer to your question in our FAQ: [link to FAQ].\n\nBest regards,\nThe Support Team"
      }
    }
  ],
  "meta": {
    "estimated_time_saved_minutes": 20,
    "runs": 0,
    "last_run": null,
    "status": "active"
  }
}

