{
  "workflow_id": "wf_7k9Lm2Xp",
  "name": "Auto-acknowledge supplier emails",
  "description": "Automatically sends a polite acknowledgement reply to supplier emails, excluding urgent requests.",
  "created_from_transcript": true,
  "trigger": {
    "type": "email_received",
    "config": {
      "from_filter": "@supplierA.com,@supplierB.net",
      "subject_filter": "urgent,ASAP",
      "match": "contains"
    }
  },
  "steps": [
    {
      "id": "step_1",
      "name": "Check if email is urgent",
      "action": "condition",
      "config": {
        "if": "{{trigger.subject}} contains 'urgent' OR {{trigger.subject}} contains 'ASAP'",
        "then": "step_3",
        "else": "step_2"
      }
    },
    {
      "id": "step_2",
      "name": "Send acknowledgement reply",
      "action": "gmail.send_email",
      "config": {
        "to": "{{trigger.from}}",
        "subject": "Re: {{trigger.subject}}",
        "body": "Hi {{extracted_name}},\n\nThanks for sending this over. We\u2019ve received it and will review it shortly. Let me know if you need anything else!\n\nBest,\nNatalie"
      }
    },
    {
      "id": "step_3",
      "name": "Flag for manual review",
      "action": "gmail.send_email",
      "config": {
        "to": "{{user.email}}",
        "subject": "Urgent: Manual review needed for {{trigger.subject}}",
        "body": "Hi Natalie,\n\nThis email from {{trigger.from}} with subject '{{trigger.subject}}' has been flagged as urgent. Please review it manually.\n\nBest,\nAria"
      }
    },
    {
      "id": "step_4",
      "name": "Extract sender's name",
      "action": "gmail.read_email",
      "config": {
        "extract_fields": [
          "extracted_name"
        ]
      },
      "output_variable": "extracted_name"
    }
  ],
  "meta": {
    "estimated_time_saved_minutes": 45,
    "runs": 0,
    "last_run": null,
    "status": "active"
  }
}

